// Captura a resposta bruta da Gemini
let resposta = $input.first().json.candidates?.[0]?.content?.parts?.[0]?.text || "";

// Normaliza
resposta = String(resposta).trim()
  .replace(/```json/gi, "")
  .replace(/```/g, "")
  .trim();

// Extrai o array JSON pelo primeiro [ e último ]
const start = resposta.indexOf("[");
const end = resposta.lastIndexOf("]");

if (start !== -1 && end !== -1 && end > start) {
  const jsonBruto = resposta.substring(start, end + 1);

  try {
    const parsed = JSON.parse(jsonBruto);

    // ✅ Se vier um array: retorna 1 item por registro
    if (Array.isArray(parsed)) {
      return parsed.map((registro, idx) => ({
        json: {
          ...registro,
          _idx: idx + 1,     // opcional (ajuda debug)
          _total: parsed.length
        }
      }));
    }

    // ✅ Se por algum motivo vier 1 objeto: retorna como 1 item
    return [{ json: parsed }];

  } catch (e) {
    return [{
      json: {
        sucesso: false,
        erro: "❌ JSON encontrado, mas inválido",
        mensagem: e.message,
        jsonExtraido: jsonBruto,
        respostaBruta: resposta
      }
    }];
  }
}

// Fallback: nenhum JSON detectado
return [{
  json: {
    sucesso: false,
    erro: "❌ Nenhum array JSON encontrado na resposta",
    respostaBruta: resposta
  }
}];

// =======================================================
// Mistral OCR -> Prompt LABOVIDA Pendências
// Adaptado para input com:
// - pages[].markdown
// - extractedText
// - pageCount
// =======================================================

const item = $input.first();
const json = item.json || {};

// -------------------------
// 1) Captura texto do novo input
// -------------------------
let conteudoBruto = "";

if (json.extractedText) {
  conteudoBruto = json.extractedText;
} else if (Array.isArray(json.pages)) {
  conteudoBruto = json.pages
    .map(p => p.markdown || "")
    .filter(Boolean)
    .join("\n\n");
} else if (json.markdown) {
  conteudoBruto = json.markdown;
} else if (json.text) {
  conteudoBruto = json.text;
}

// -------------------------
// 2) Normalização base
// -------------------------
let texto = String(conteudoBruto)
  .replace(/\r\n/g, "\n")
  .replace(/\r/g, "\n")
  .replace(/"/g, "'")
  .replace(/[\u0000-\u001F\u007F-\u009F]/g, "")
  .trim();

// -------------------------
// 3) Limpeza segura
// -------------------------
function limparTextoOCR(s) {
  return String(s || "")
    .replace(/^\s*LABOVIDA\s*$/gim, "")
    .replace(/Bancada\s*:\s*/gi, " ")
    .replace(/Relat[oó]rio\s+de\s+Pend[eê]ncias/gi, " ")
    .replace(/Resumo\s*:\s*Pacientes\s*atendidos\s*:\s*\d+/gi, " ")
    .replace(/Pacientes\s*atendidos\s*:\s*\d+/gi, " ")
    .replace(/Data\s*de\s*impress[aã]o\s*:\s*\d{2}\/\d{2}\/\d{4}/gi, " ")
    .replace(/Usu[aá]rio\s*:\s*[A-ZÀ-Ú\s]+/gi, " ")
    .replace(/\|\s*-+\s*/g, " ")
    .replace(/\|\s*/g, " | ")
    .replace(/\s{2,}/g, " ")
    .trim();
}

const conteudoSemCabecalho = limparTextoOCR(texto);

// -------------------------
// 4) Nome do arquivo
// -------------------------
const nomeArquivo =
  json.arquivo ||
  json.nome ||
  json.fileName ||
  json.filename ||
  "sem_nome.pdf";

// -------------------------
// 5) Corpo final
// -------------------------
const conteudoFinal = `🗂️ Documento: ${nomeArquivo}\n"""${conteudoSemCabecalho}"""`;

// =======================================================
// PROMPT
// =======================================================
return {
  json: {
    contents: [
      {
        role: "user",
        parts: [
          {
            text: `
Você é um extrator de dados. Sua tarefa é transformar TEXTO OCR de "LABOVIDA Bancada: Relatório de Pendências" em JSON estruturado.

REGRAS IMPORTANTES:
1) Extraia CADA REGISTRO de paciente encontrado no texto.
2) O texto pode vir em formato de tabela markdown com separador "|".
3) Cada registro segue aproximadamente:
   area | posto | dataCadastro | registroCadastro | nomePaciente | exames...
4) Retorne APENAS JSON válido. Não use markdown. Não explique.

FORMATO DE SAÍDA:
[
  {
    "area": <number>,
    "posto": <number>,
    "dataCadastro": "dd/mm/aaaa",
    "registroCadastro": "<string_apenas_digitos>",
    "nomePaciente": "<string>",
    "exame": {
      "ex1": "<sigla>(LIB)",
      "ex2": "...",
      ...
    }
  }
]

COMO EXTRAIR:
- "area" = primeiro número da linha.
- "posto" = segundo número da linha.
- "dataCadastro" = data no formato dd/mm/aaaa.
- "registroCadastro" = número após a data. Manter somente dígitos.
- "nomePaciente" = texto após registroCadastro e antes do primeiro exame.
- Exames = tokens como B12(LIB), T4L(LIB), 25OHD(LIB), HB1AC(LIB), GLIS(LIB), SU(LIB), etc.
- Também aceite exames com "(6)", como B12(6), HTLV(6), GLI(6).
- Se OCR separar o exame, normalize:
  - "GLIS (LIB)" => "GLIS(LIB)"
  - "HP (LIB)" => "HP(LIB)"
  - "TGP (LIB)" => "TGP(LIB)"
- Mantenha a ordem dos exames e enumere como ex1, ex2, ex3...
- Se não houver exames, retorne "exame": {}.
- Não duplique registros idênticos.

SEGMENTAÇÃO:
- Um novo registro começa quando aparecer:
  area + posto + data + registro
  Exemplo: 6 | 35 | 18/04/2026 | 3567833

AGORA EXTRAIA DO TEXTO ABAIXO:

${conteudoFinal}
            `.trim(),
          },
        ],
      },
    ],
  },
};

// Pega TODOS os itens de entrada (caso você já tenha vários pacientes) e separa um exame por item
const itens = $input.all();

const saida = [];

for (const it of itens) {
  const j = it.json || {};

  const base = {
    area: j.area ?? null,
    posto: j.posto ?? null,
    dataCadastro: j.dataCadastro ?? "",
    registroCadastro: j.registroCadastro ?? "",
    nomePaciente: j.nomePaciente ?? "",
    _idx: j._idx ?? null,
    _total: j._total ?? null, // opcional (remova se não quiser)
  };

  const examesObj = j.exame && typeof j.exame === "object" ? j.exame : {};

  // Ordena ex1, ex2, ex3... corretamente
  const keysOrdenadas = Object.keys(examesObj).sort((a, b) => {
    const na = parseInt(a.replace(/\D/g, ""), 10) || 0;
    const nb = parseInt(b.replace(/\D/g, ""), 10) || 0;
    return na - nb;
  });

  // Se não tiver exames, ainda retorna 1 item (opcional)
  if (keysOrdenadas.length === 0) {
    saida.push({
      json: {
        ...base,
        exameKey: "",
        exameValor: "",
      },
    });
    continue;
  }

  // Cria 1 item por exame
  for (const k of keysOrdenadas) {
    saida.push({
      json: {
        ...base,
        exameKey: k,                 // ex1, ex2...
        exameValor: String(examesObj[k] ?? "").trim(), // "B12(ENV)"
      },
    });
  }
}

return saida;

// cria Status exame e sistema 
//Processa todos os itens (1 por exame)
const itens = $input.all();

// Extrai sigla (antes do parêntese)
function extrairSigla(exame) {
  const txt = String(exame || "").trim();

  // Pega tudo antes do primeiro "("
  const idx = txt.indexOf("(");
  if (idx === -1) return txt;

  return txt.substring(0, idx).trim();
}

// Classifica status pelo código entre parênteses
function classificarStatus(exame) {
  const txt = String(exame || "").toUpperCase();

  // Extrai o que está entre parênteses: (ENV), (PEN), (DIG), (9) etc
  const match = txt.match(/\(([^)]+)\)/);
  const codigo = match ? match[1] : "";

  switch (codigo) {
    case "ENV":
      return "EXAME ENVIADO";
    case "PEN":
      return "EXAME INTERNO";
    case "DIG":
      return "FALTA LIBERAR RESULTADO";
    case "9":
      return "ENVIO MANUAL";
    default:
      return "STATUS DESCONHECIDO";
  }
}

return itens.map(it => {
  const j = it.json || {};
  const exameValor = j.exameValor || "";

  return {
    json: {
      ...j,
      sigla: extrairSigla(exameValor),     // ✅ NOVA VARIÁVEL
      statusExame: classificarStatus(exameValor),
      sistema: "AT&TIC",
    }
  };
});

// =======================================================
// Corrige padrões:
// - 250HD    -> 25OHD
// - 25O0HD   -> 25OHD
// - HB1|AC   -> HB1AC
// + adiciona dataHoraExecucao
// =======================================================

const itens = $input.all();

const FIELDS = ["sigla", "exameValor", "DESCRIÇÃO DO EXAME"];

// função de correção
const fix = (v) =>
  String(v ?? "")
    .replace(/25O0HD/gi, "25OHD")
    .replace(/250HD/gi, "25OHD")
    .replace(/HB1[\|I\-\s_]*AC/gi, "HB1AC")
    .replace(/\bDAGSRH\b/gi, "GSRH")
    .replace(/\bDOCREA\b/gi, "CRE");

// função data BR
function dataHoraBR() {
  const d = new Date();
  const pad = (n) => String(n).padStart(2, "0");

  return `${pad(d.getDate())}/${pad(d.getMonth() + 1)}/${d.getFullYear()} ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
}

return itens.map((item) => {
  const json = { ...item.json };

  // aplica correção nos campos
  for (const f of FIELDS) {
    if (json[f] !== undefined && json[f] !== null) {
      json[f] = fix(json[f]);
    }
  }

  // adiciona timestamp
  json.dataHoraExecucao = dataHoraBR();

  return { json };
});

// ======================================================
// MATCH por 3 chaves
// ✅ Retorna SOMENTE matches
// ❌ Se não houver nenhum match → retorna 1 item informando
// ======================================================

const norm = (v) =>
  String(v ?? "")
    .replace(/\u00A0/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .toLowerCase();

function extrairDataBR(valor) {
  if (!valor) return "";
  const m = String(valor).match(/\b(\d{2}\/\d{2}\/\d{4})\b/);
  return m ? m[1] : String(valor).trim();
}

function makeKeyFromInput1(row) {
  const data = norm(extrairDataBR(row["dataCadastro"]));
  const codigo = norm(row["registroCadastro"]);
  const exame = norm(row["sigla"]);
  return `${data}♦${codigo}♦${exame}`;
}

function makeKeyFromInput2(row) {
  const data = norm(extrairDataBR(row["Data do Cadastro"]));
  const codigo = norm(row["Registro do Paciente"]);
  const exame = norm(row["SIGLA"]);
  return `${data}♦${codigo}♦${exame}`;
}

const input1 = $input.all(0);
const input2 = $input.all(1);

const index = new Map();

// indexa input1
for (const item of input1) {
  const row1 = item.json || {};
  const key = makeKeyFromInput1(row1);

  if (!key || key === "♦♦") continue;

  if (!index.has(key)) index.set(key, []);
  index.get(key).push(row1);
}

const output = [];

// busca matches
for (const item of input2) {
  const row2 = item.json || {};
  const key = makeKeyFromInput2(row2);

  if (!key || key === "♦♦") continue;

  const matches = index.get(key);
  if (!matches) continue;

  for (const row1 of matches) {
    output.push({
      json: {
        teveMatch: true,
        chaveMatch: key,

        ...Object.fromEntries(
          Object.entries(row1).map(([k, v]) => [`input1_${k}`, v])
        ),

        ...Object.fromEntries(
          Object.entries(row2).map(([k, v]) => [`input2_${k}`, v])
        ),
      }
    });
  }
}

// 👉 regra final
if (output.length === 0) {
  return [
    {
      json: {
        teveMatch: false,
        mensagem: "Nenhum match encontrado"
      }
    }
  ];
}

return output;

return [
  {
    json: {
      sucesso: false,
      fallbackUsado: true,
      mensagem: "Nenhum dos dois requests Gemini retornou com sucesso"
    }
  }
];

// =======================================================
// OCR -> Prompt (limpeza segura de cabeçalho/rodapé LABOVIDA)
// - Remove SOMENTE no INÍCIO/FIM do texto (head/tail):
//   * "LABOVIDA"
//   * "Resumo: Pacientes atendidos: N"
//   * "Data de impressão: dd/mm/aaaa Usuário: ..."
// - Não remove nada do "miolo" do OCR
// =======================================================

const item = $input.first();
const conteudoBruto = item?.json?.extractedText || "";

// -------------------------
// 1) normalização base (sem apagar conteúdo útil)
// -------------------------
let texto = String(conteudoBruto)
  .replace(/\r\n/g, "\n")
  .replace(/\r/g, "\n")
  .replace(/"/g, "'") // se você não quiser trocar aspas, remova esta linha
  .replace(/[\u0000-\u001F\u007F-\u009F]/g, "") // remove controles
  .trim();

// -------------------------
// 2) função: limpa cabeçalho/rodapé apenas em head/tail
// -------------------------
function limparCabecalhoRodape(s, headSize = 600, tailSize = 600) {
  const len = s.length;

  const head = s.slice(0, Math.min(headSize, len));
  const mid = s.slice(Math.min(headSize, len), Math.max(len - tailSize, Math.min(headSize, len)));
  const tail = s.slice(Math.max(len - tailSize, 0));

  const limparBloco = (bloco) => {
    let b = bloco;

    // remove "LABOVIDA" quando aparece como linha isolada (mais seguro)
    b = b.replace(/^\s*LABOVIDA\s*$/gim, "");

    // remove "LABOVIDA" se estiver grudado no começo do bloco (cabeçalho)
    b = b.replace(/^\s*LABOVIDA\s*/i, "");

    // remove "LABOVIDA" se estiver grudado no fim do bloco (rodapé)
    b = b.replace(/\s*LABOVIDA\s*$/i, "");

    // remove "Resumo: Pacientes atendidos: N" (mesmo colado)
    b = b.replace(/Resumo\s*:\s*Pacientes\s*atendidos\s*:\s*\d+\s*/gi, " ");

    // remove "Data de impressão: dd/mm/aaaa Usuário: XXXXX" (mesmo colado)
    // aqui removemos só o trecho de "Data..." até o final do nome do usuário
    // limitando pelo próximo marcador comum (quebra/aspas/fim)
    b = b.replace(
      /Data\s*de\s*impress[aã]o\s*:\s*\d{2}\/\d{2}\/\d{4}\s*Usu[aá]rio\s*:\s*.*?(?=(\n|'''|"""+|$))/gi,
      " "
    );

    // limpa espaços
    b = b.replace(/\s{2,}/g, " ").trim();

    return b;
  };

  const head2 = limparBloco(head);
  const tail2 = limparBloco(tail);

  // remonta preservando o miolo intacto
  const juntado = [head2, mid, tail2].join(" ");

  return juntado
    .replace(/\n+/g, " ")
    .replace(/\s{2,}/g, " ")
    .trim();
}

// aplica limpeza segura
const conteudoSemCabecalho = limparCabecalhoRodape(texto);

// -------------------------
// nome do arquivo
// -------------------------
const nomeArquivo =
  item?.json?.arquivo ||
  item?.json?.nome ||
  "sem_nome.pdf";

// -------------------------
// corpo final para o prompt
// -------------------------
const conteudoFinal = `🗂️ Documento: ${nomeArquivo}\n"""${conteudoSemCabecalho}"""`;

// =======================================================
// PROMPT
// =======================================================
return {
  json: {
    contents: [
      {
        role: "user",
        parts: [
          {
            text: `
Você é um extrator de dados. Sua tarefa é transformar TEXTO OCR de "LABOVIDA Bancada: Relatório de Pendências" em JSON estruturado.

REGRAS IMPORTANTES (obrigatórias):
1) Você receberá um ou mais blocos. Cada bloco começa com "LABOVIDA" e termina com "LABOVIDA".
2) Extraia CADA REGISTRO (cada paciente/linha) encontrado no texto.
3) Cada registro SEMPRE tem esta estrutura aproximada (OCR pode quebrar linhas):
   <area> <posto> <dataCadastro dd/mm/aaaa> <registroCadastro> — <nomePaciente> <exames...>
   - Por exemplo: "\n1\n12\n24/03/2026\n12233269\nMARIA ELIZIANE\nCREA(ENV)"
   - O traço pode aparecer como "—" ou "-" ou pode ficar deslocado.
   - O registroCadastro aparecer antes do traço (ex: "12232024 — ADRIANA ...").
5) O posto é o bloco anterior que vem antes de \n dd/mm/aaaa e depois \n
6) Retorne APENAS um JSON válido (nada de explicações, nada de markdown, nada de texto fora do JSON).

FORMATO DE SAÍDA (obrigatório):
[
  {
    "area": <number>,
    "posto": <number>,
    "dataCadastro": "dd/mm/aaaa",
    "registroCadastro": "<string_apenas_digitos>",
    "nomePaciente": "<string>",
    "exame": {
      "ex1": "<sigla>(ENV)",
      "ex2": "...",
      ...
    }
  },
  ...
]

NORMALIZAÇÃO / LIMPEZA:
- "area" = primeiro número do registro. "posto" = segundo número do registro.
- "registroCadastro": manter SOMENTE dígitos (remover espaços, hífens, "—").
- "nomePaciente": manter como aparece (pode ter acentos). Remover excesso de espaços. Não inventar nomes.
- Exames: detectar tokens que pareçam exame, normalmente algo como "B12(ENV)", "T4L(ENV)", "250HD(ENV)", "HB1AC(ENV)" etc.
  - Se OCR quebrar (ex: "CRE (ENV)" ou "ERI (ENV)" ou "TRIENV)" ), una e normalize para o padrão "<TEXTO>(ENV)" quando ficar claro.
  - Aceite variações OCR como "25O0HD(ENV)" (com letra O) e mantenha exatamente como aparece.
- Ordem: manter a ordem em que os exames aparecem no texto do registro e enumerar ex1..exN.

SEGMENTAÇÃO (como achar onde começa/termina um registro):
- Um novo registro começa quando aparecer um padrão com DOIS números seguidos + data:
  Ex: /\\b(\\d+)\\s+(\\d+)\\s+(\\d{2}\\/\\d{2}\\/\\d{4})\\b/
- O registro termina imediatamente antes do próximo início de registro OU fim do documento.

TRATAMENTO DE FALTAS:
- Se um registro não tiver exames, retorne "exame": {}.
- Se não conseguir achar registroCadastro com segurança, ainda retorne o registro com "registroCadastro": "" (string vazia).
- Não duplicar registros idênticos (mesmos: area, posto, dataCadastro, registroCadastro, nomePaciente).

AGORA EXTRAIA DO TEXTO ABAIXO:

${conteudoFinal}
            `.trim(),
          },
        ],
      },
    ],
  },
};

