const input1 = $input.all(0);
const input2 = $input.all(1);

const index = new Set();

// indexa input1
for (const item of input1) {
  const row1 = item.json || {};
  const key = makeKeyFromInput1(row1);

  if (!key || key === "♦♦") continue;

  index.add(key);
}

const output = [];

// retorna os que NÃO deram match no input2
for (const item of input2) {
  const row2 = item.json || {};
  const key = makeKeyFromInput2(row2);

  if (!key || key === "♦♦") continue;

  const teveMatch = index.has(key);

  if (!teveMatch) {
    output.push({
      json: {
        teveMatch: false,
        chaveMatch: key,
        motivo: "Registro existe no input2, mas não foi encontrado no input1",

        ...Object.fromEntries(
          Object.entries(row2).map(([k, v]) => [`input2_${k}`, v])
        ),
      }
    });
  }
}

// regra final
if (output.length === 0) {
  return [
    {
      json: {
        teveMatch: true,
        mensagem: "Todos os registros do input2 deram match com o input1"
      }
    }
  ];
