return output;

let resposta =
  $input.first().json.text ||
  $input.first().json.output ||
  $input.first().json.response ||
  "";

resposta = String(resposta)
  .trim()
  .replace(/```json/gi, "")
  .replace(/```/g, "")
  .trim();

const start = resposta.indexOf("[");
const end = resposta.lastIndexOf("]");

if (start === -1 || end === -1 || end <= start) {
  return [{
    json: {
      sucesso: false,
      erro: "Nenhum array JSON encontrado na resposta da IA",
      respostaBruta: resposta
    }
  }];
}

const jsonBruto = resposta.substring(start, end + 1);

let parsed;

try {
  parsed = JSON.parse(jsonBruto);
} catch (e) {
  return [{
    json: {
      sucesso: false,
      erro: "JSON encontrado, mas inválido",
      mensagem: e.message,
      jsonExtraido: jsonBruto,
      respostaBruta: resposta
    }
  }];
}

if (!Array.isArray(parsed)) {
  parsed = [parsed];
}

return parsed.map((registro, idx) => ({
  json: {
    ...registro,
    _idx: idx + 1,
    _total: parsed.length
  }
}));
